```typescript
private _translateGridPositionsToTablePositions(): void {
  if (!this._grid?.Rows) {
    return;
  }

  const overflowingColumns: { columnIndex: number, rowsRemaining: number }[] = [];

  for (const row of this._grid.Rows) {
    if (!row.Cells) {
      continue;
    }

    // Sort cells by their column index to handle overlapping in a more predictable manner
    row.Cells.sort((a, b) => a.ColumnIndex - b.ColumnIndex);

    let cellsRemoved = 0;
    for (let i = 0; i < row.Cells.length; i++) {
      const cell = row.Cells[i];

      // Check if the current cell overlaps with any previously identified overflowing columns
      const overlaps = overflowingColumns.find(
        (overflowingColumn) => overflowingColumn.columnIndex === cell.ColumnIndex && overflowingColumn.rowsRemaining > 0
      );

      if (overlaps) {
        // If an overlap is found, remove the current cell and decrement the rows remaining for the overflowing column
        row.Cells.splice(i, 1);
        cellsRemoved++;
        overlaps.rowsRemaining--;
        continue; // Skip to the next cell after removing the current one
      }

      // If the cell has components with row spans greater than 1, add it to the overflowingColumns list
      if (cell.Components) {
        if (cell.RowSpan > 1 || cell.Components.some((c) => c.RowSpan > 1)) {
          overflowingColumns.push({ columnIndex: cell.ColumnIndex, rowsRemaining: cell.RowSpan });
        }
      }
    }

    // Remove any overflowing columns that have been fully resolved
    overflowingColumns = overflowingColumns.filter((column) => column.rowsRemaining > 0);
  }
}
